// XP thresholds per level
const XP_LEVELS = [
  { level: 1, label: 'Beginner',           labelKey: 'xpBeginner' as const,          xpNeeded: 0    },
  { level: 2, label: 'Elementary',         labelKey: 'xpElementary' as const,        xpNeeded: 100  },
  { level: 3, label: 'Pre-Intermediate',   labelKey: 'xpPreIntermediate' as const,   xpNeeded: 300  },
  { level: 4, label: 'Intermediate',       labelKey: 'xpIntermediate' as const,      xpNeeded: 600  },
  { level: 5, label: 'Upper-Intermediate', labelKey: 'xpUpperIntermediate' as const, xpNeeded: 1000 },
  { level: 6, label: 'Advanced',           labelKey: 'xpAdvanced' as const,          xpNeeded: 1500 },
  { level: 7, label: 'Proficient',         labelKey: 'xpProficient' as const,        xpNeeded: 2200 },
  { level: 8, label: 'Master',             labelKey: 'xpMaster' as const,            xpNeeded: 3000 },
];

function getXPLevel(xp) {
  let current = XP_LEVELS[0];
  let next = XP_LEVELS[1];
  for (let i = XP_LEVELS.length - 1; i >= 0; i--) {
    if (xp >= XP_LEVELS[i].xpNeeded) {
      current = XP_LEVELS[i];
      next = XP_LEVELS[i + 1] || null;
      break;
    }
  }
  const progress = next
    ? ((xp - current.xpNeeded) / (next.xpNeeded - current.xpNeeded)) * 100
    : 100;
  return { current, next, progress: Math.min(100, Math.round(progress)) };
}

function scoreColor(score, C) {
  if (score >= 90) return C.emerald || '#34D399';
  if (score >= 75) return '#60A5FA';
  if (score >= 60) return '#FBBF24';
  return C.red || '#F87171';
}

function escapePdfHtml(value) {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function formatPdfTableDate(value) {
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return '-';
  return `${date.getFullYear()}/${String(date.getMonth() + 1).padStart(2, '0')}/${String(date.getDate()).padStart(2, '0')}`;
}

// ── Score ring component ──────────────────────────────────────────────────────
function ScoreRing({ score, size = 80, color, C }) {
  const r = (size - 8) / 2;
  const circ = 2 * Math.PI * r;
  const dash = (score / 100) * circ;
  return (
    <View style={{ width: size, height: size, alignItems: 'center', justifyContent: 'center' }}>
      <svg width={size} height={size} style={{ position: 'absolute' }}>
        <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={C.border || '#374151'} strokeWidth={5} opacity={0.3} />
        <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={color} strokeWidth={5}
          strokeDasharray={`${dash} ${circ}`} strokeLinecap="round"
          transform={`rotate(-90 ${size/2} ${size/2})`} />
      </svg>
      <Text style={{ fontSize: scaledFont(size * 0.25), fontWeight: '800', color }}>{score}</Text>
    </View>
  );
}

// ── Streak heatmap dots ───────────────────────────────────────────────────────
function WeekHeatmap({ streak, C, p, isRTL }: { streak: number; C: any; p: ProgressStrings; isRTL: boolean }) {
  const days = [p.dayMon, p.dayTue, p.dayWed, p.dayThu, p.dayFri, p.daySat, p.daySun];
  const today = new Date().getDay(); // 0=Sun
  const dayOfWeek = today === 0 ? 6 : today - 1; // Mon=0
  return (
    <View style={{ flexDirection: isRTL ? 'row-reverse' : 'row', gap: 4, alignItems: 'center' }}>
      {days.map((d, i) => {
        const active = i <= dayOfWeek && streak > 0;
        return (
          <View key={i} style={{ alignItems: 'center', gap: 3 }}>
            <View style={{
              width: 28, height: 28, borderRadius: 6,
              backgroundColor: active ? '#FB923C' : (C.card || '#1F2937'),
              borderWidth: 1,
              borderColor: active ? '#FB923C' : (C.border || '#374151') + '40',
              alignItems: 'center', justifyContent: 'center',
            }}>
              {active && <Flame size={12} color="#fff" />}
            </View>
            <Text style={{ fontSize: 9, color: C.textMuted, fontWeight: '600' }}>{d}</Text>
          </View>
        );
      })}
    </View>
  );
}

