      setStreak(streakVal);
      setBestStreak(bestStreakVal);

      const totalSecs = await getTotalTimeSeconds();
      setTotalSeconds(totalSecs);

      // Load all exercise data
      const data = {};
      let allScores    = [];
      const mistakeMap = {};

      for (const ex of ALL_EXERCISES) {
        const [rRaw, wRaw] = await Promise.all([
          AsyncStorage.getItem(`progress_recent_${ex.id}`),
          AsyncStorage.getItem(`progress_weak_${ex.id}`),
        ]);
        const recent  = rRaw ? JSON.parse(rRaw) : [];
        const weak    = wRaw ? JSON.parse(wRaw) : [];
        const scores  = recent.filter(r => r.score !== undefined).map(r => r.score);
        const avg     = scores.length > 0 ? Math.round(scores.reduce((a, b) => a + b, 0) / scores.length) : null;
        const best    = scores.length > 0 ? Math.max(...scores) : null;
        const lastDate = recent.length > 0 ? recent[0].date : null;

        data[ex.id] = { recent, weak, avg, best, sessions: recent.length, lastDate };

        if (avg !== null) allScores.push(avg);

        // Aggregate weak areas into mistake categories
        for (const w of weak) {
          const cat = w.category || 'General';
          if (!mistakeMap[cat]) mistakeMap[cat] = { category: cat, frequency: 0, exercises: new Set() };
          mistakeMap[cat].frequency += (w.frequency || 1);
          mistakeMap[cat].exercises.add(p[ex.labelKey]);
        }
      }

      setExerciseData(data);
      setOverallAvg(allScores.length > 0 ? Math.round(allScores.reduce((a, b) => a + b, 0) / allScores.length) : 0);

      // Sort mistake categories by frequency
      const ranked = Object.values(mistakeMap)
        .sort((a, b) => b.frequency - a.frequency)
        .slice(0, 6)
        .map(m => ({ ...m, exercises: Array.from(m.exercises) }));
      setMistakeRanking(ranked);

